class IoTHttpClient private constructor() {

    companion object {
        private const val TAG = "IoTHttpClient"
        private const val CLOUD_BASE_URL = "https://api.example.com"
        private const val LOCAL_NETWORK_PREFIX = "192.168."
        private const val DEFAULT_TIMEOUT_SECONDS = 10L
        private const val LOCAL_TIMEOUT_SECONDS = 5L

        @Volatile
        private var instance: IoTHttpClient? = null

        fun getInstance(): IoTHttpClient {
            return instance ?: synchronized(this) {
                instance ?: IoTHttpClient().also { instance = it }
            }
        }
    }

    private val JSON_MEDIA_TYPE = "application/json; charset=utf-8".toMediaType()

    private val cloudClient: OkHttpClient by lazy {
        OkHttpClient.Builder()
            .connectTimeout(DEFAULT_TIMEOUT_SECONDS, TimeUnit.SECONDS)
            .readTimeout(DEFAULT_TIMEOUT_SECONDS, TimeUnit.SECONDS)
            .writeTimeout(DEFAULT_TIMEOUT_SECONDS, TimeUnit.SECONDS)
            .addInterceptor(LoggingInterceptor())
            .addInterceptor(CloudAuthInterceptor())
            .retryOnConnectionFailure(true)
            .build()
    }

    private val localHttpClient: OkHttpClient by lazy {
        createLocalClient(trustAllCerts = false)
    }

    private val localHttpsUnsafeClient: OkHttpClient by lazy {
        createLocalClient(trustAllCerts = true)
    }

    private fun createLocalClient(trustAllCerts: Boolean): OkHttpClient {
        val builder = OkHttpClient.Builder()
            .connectTimeout(LOCAL_TIMEOUT_SECONDS, TimeUnit.SECONDS)
            .readTimeout(LOCAL_TIMEOUT_SECONDS, TimeUnit.SECONDS)
            .writeTimeout(LOCAL_TIMEOUT_SECONDS, TimeUnit.SECONDS)
            .addInterceptor(LoggingInterceptor())
            .retryOnConnectionFailure(true)

        if (trustAllCerts) {
            val trustManager = object : X509TrustManager {
                override fun checkClientTrusted(chain: Array<out X509Certificate>?, authType: String?) {}
                override fun checkServerTrusted(chain: Array<out X509Certificate>?, authType: String?) {}
                override fun getAcceptedIssuers(): Array<X509Certificate> = arrayOf()
            }

            val sslContext = SSLContext.getInstance("TLS")
            sslContext.init(null, arrayOf<TrustManager>(trustManager), SecureRandom())

            builder.sslSocketFactory(sslContext.socketFactory, trustManager)
            builder.hostnameVerifier { _, _ -> true }
        }

        return builder.build()
    }

    private fun getClientForUrl(url: String): OkHttpClient {
        return when {
            url.contains(LOCAL_NETWORK_PREFIX) && url.startsWith("https") -> localHttpsUnsafeClient
            url.contains(LOCAL_NETWORK_PREFIX) -> localHttpClient
            else -> cloudClient
        }
    }

    private fun isLocalDevice(url: String): Boolean {
        return url.contains(LOCAL_NETWORK_PREFIX)
    }

