    // Synchronous versions

    fun getSync(url: String, headers: Map<String, String>? = null): IoTResponse {
        val requestBuilder = Request.Builder().url(url).get()
        headers?.forEach { (key, value) -> requestBuilder.addHeader(key, value) }
        return executeRequestSync(requestBuilder.build())
    }

    fun postSync(
        url: String,
        jsonBody: JSONObject,
        headers: Map<String, String>? = null
    ): IoTResponse {
        val body = jsonBody.toString().toRequestBody(JSON_MEDIA_TYPE)
        val requestBuilder = Request.Builder().url(url).post(body)
        headers?.forEach { (key, value) -> requestBuilder.addHeader(key, value) }
        return executeRequestSync(requestBuilder.build())
    }

    private fun executeRequest(request: Request, callback: IoTResponseCallback) {
        val client = getClientForUrl(request.url.toString())

        client.newCall(request).enqueue(object : Callback {
            override fun onFailure(call: Call, e: IOException) {
                Log.e(TAG, "Request failed: ${request.url}", e)
                callback.onError(IoTError(
                    message = e.message ?: "Unknown error",
                    exception = e,
                    url = request.url.toString(),
                    isLocalDevice = isLocalDevice(request.url.toString())
                ))
            }

            override fun onResponse(call: Call, response: Response) {
                response.use {
                    val responseBody = it.body?.string()
                    val iotResponse = IoTResponse(
                        statusCode = it.code,
                        body = responseBody,
                        headers = parseHeaders(it.headers),
                        url = request.url.toString(),
                        isLocalDevice = isLocalDevice(request.url.toString()),
                        isSuccessful = it.isSuccessful
                    )

                    if (it.isSuccessful) {
                        callback.onSuccess(iotResponse)
                    } else {
                        callback.onError(IoTError(
                            message = "HTTP ${it.code}: ${it.message}",
                            statusCode = it.code,
                            responseBody = responseBody,
                            url = request.url.toString(),
                            isLocalDevice = isLocalDevice(request.url.toString())
                        ))
                    }
                }
            }
        })
    }

    private fun executeRequestSync(request: Request): IoTResponse {
        val client = getClientForUrl(request.url.toString())
        val response = client.newCall(request).execute()
        response.use {
            val responseBody = it.body?.string()
            return IoTResponse(
                statusCode = it.code,
                body = responseBody,
                headers = parseHeaders(it.headers),
                url = request.url.toString(),
                isLocalDevice = isLocalDevice(request.url.toString()),
                isSuccessful = it.isSuccessful
            )
        }
    }

    private fun parseHeaders(headers: Headers): Map<String, String> {
        val map = mutableMapOf<String, String>()
        for (i in 0 until headers.size) {
            map[headers.name(i)] = headers.value(i)
        }
        return map
    }

    // --- Device Discovery ---

    fun discoverDevices(
        subnet: String = "192.168.1",
        port: Int = 80,
        path: String = "/status",
        useHttps: Boolean = false,
        callback: DeviceDiscoveryCallback
    ) {
        val discoveredDevices = mutableListOf<DeviceInfo>()
        var completedCount = 0
        val totalHosts = 254

        for (i in 1..254) {
            val ip = "$subnet.$i"
            val scheme = if (useHttps) "https" else "http"
            val url = "$scheme://$ip:$port$path"

            val quickClient = OkHttpClient.Builder()
                .connectTimeout(1, TimeUnit.SECONDS)
                .readTimeout(1, TimeUnit.SECONDS)
                .build()

            val request = Request.Builder().url(url).get().build()

            quickClient.newCall(request).enqueue(object : Callback {
                override fun onFailure(call: Call, e: IOException) {
                    synchronized(discoveredDevices) {
                        completedCount++
                        if (completedCount >= totalHosts) {
                            callback.onDiscoveryComplete(discoveredDevices.toList())
                        }
                    }
                }

                override fun onResponse(call: Call, response: Response) {
                    response.use {
                        val body = it.body?.string()
                        synchronized(discoveredDevices) {
                            val device = DeviceInfo(
                                ip = ip,
                                port = port,
                                statusCode = it.code,
                                responseBody = body,
                                supportsHttps = useHttps
                            )
                            discoveredDevices.add(device)
                            callback.onDeviceFound(device)
                            completedCount++
                            if (completedCount >= totalHosts) {
                                callback.onDiscoveryComplete(discoveredDevices.toList())
                            }
                        }
                    }
                }
            })
        }
    }

    // --- Interceptors ---

    private class LoggingInterceptor : Interceptor {
        override fun intercept(chain: Interceptor.Chain): Response {
            val request = chain.request()
            val startTime = System.nanoTime()
            Log.d(TAG, "--> ${request.method} ${request.url}")

            val response = chain.proceed(request)
            val duration = (System.nanoTime() - startTime) / 1_000_000

            Log.d(TAG, "<-- ${response.code} ${request.url} (${duration}ms)")
            return response
        }
    }

    private class CloudAuthInterceptor : Interceptor {
        override fun intercept(chain: Interceptor.Chain): Response {
            val original = chain.request()

            if (original.url.toString().startsWith(CLOUD_BASE_URL)) {
                val token = TokenManager.getToken()
                if (token != null) {
                    val authenticatedRequest = original.newBuilder()
                        .addHeader("Authorization", "Bearer $token")
                        .addHeader("Content-Type", "application/json")
                        .build()
                    return chain.proceed(authenticatedRequest)
                }
            }

            return chain.proceed(original)
        }
    }
