}

data class IoTError(
    val message: String,
    val statusCode: Int? = null,
    val responseBody: String? = null,
    val exception: Exception? = null,
    val url: String,
    val isLocalDevice: Boolean
)

data class DeviceInfo(
    val ip: String,
    val port: Int,
    val statusCode: Int,
    val responseBody: String?,
    val supportsHttps: Boolean
)

// --- Callbacks ---

interface IoTResponseCallback {
    fun onSuccess(response: IoTResponse)
    fun onError(error: IoTError)
}

interface DeviceDiscoveryCallback {
    fun onDeviceFound(device: DeviceInfo)
    fun onDiscoveryComplete(devices: List<DeviceInfo>)
}

